/**
 * GitHub Dark-inspired CSS for the report website.
 * Self-contained — no external CDN dependencies.
 * Supports dark (default) and light themes, sidebar navigation, responsive layout.
 */

export const REPORT_CSS = `
:root {
  --bg: #0d1117;
  --bg-secondary: #161b22;
  --bg-card: #21262d;
  --border: #30363d;
  --text: #e6edf3;
  --text-muted: #8b949e;
  --accent: #58a6ff;
  --accent-hover: #79b8ff;
  --green-0: #161b22;
  --green-1: #0e4429;
  --green-2: #006d32;
  --green-3: #26a641;
  --green-4: #39d353;
  --user-bg: #1c2d3e;
  --user-border: #388bfd44;
  --assistant-bg: #1c1c1c;
  --assistant-border: #30363d;
  --code-bg: #161b22;
  --badge-codex: #1f6feb;
  --badge-claude: #6e40c9;
  --badge-gemini: #1a7f37;
  --danger: #f85149;
  --warning: #d29922;
  --success: #3fb950;
  --sidebar-width: 240px;
  --font-mono: 'SF Mono', 'Consolas', 'Liberation Mono', 'Menlo', monospace;
}

[data-theme="light"] {
  --bg: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-card: #ffffff;
  --border: #d0d7de;
  --text: #1f2328;
  --text-muted: #636c76;
  --accent: #0969da;
  --accent-hover: #0550ae;
  --user-bg: #ddf4ff;
  --user-border: #54aeff44;
  --assistant-bg: #f6f8fa;
  --assistant-border: #d0d7de;
  --code-bg: #f6f8fa;
  --green-0: #f6f8fa;
  --green-1: #acf2bd;
  --green-2: #40c463;
  --green-3: #30a14e;
  --green-4: #216e39;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); text-decoration: underline; }

code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--code-bg);
  padding: 0.15em 0.4em;
  border-radius: 4px;
  border: 1px solid var(--border);
}

pre {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75rem 0;
}

pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.875rem;
}

h1, h2, h3, h4, h5, h6 {
  color: var(--text);
  line-height: 1.3;
  margin-bottom: 0.5rem;
}

h1 { font-size: 1.75rem; }
h2 { font-size: 1.375rem; border-bottom: 1px solid var(--border); padding-bottom: 0.4rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }
h3 { font-size: 1.125rem; }

p { margin-bottom: 0.75rem; }

ul, ol { padding-left: 1.5rem; margin-bottom: 0.75rem; }
li { margin-bottom: 0.25rem; }

table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
th, td { padding: 0.5rem 0.75rem; text-align: left; border-bottom: 1px solid var(--border); }
th { color: var(--text-muted); font-weight: 600; font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.05em; background: var(--bg-secondary); }
tr:hover td { background: var(--bg-secondary); }

/* ── Mobile topbar ── */
.topbar {
  display: none;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  padding: 0 1rem;
  align-items: center;
  gap: 0.75rem;
  height: 48px;
  position: sticky;
  top: 0;
  z-index: 200;
}

.topbar-brand {
  font-weight: 700;
  font-size: 0.95rem;
  color: var(--text);
  flex: 1;
}

.topbar-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.hamburger, .theme-toggle-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 6px;
  padding: 0.3rem 0.5rem;
  cursor: pointer;
  font-size: 1rem;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.hamburger:hover, .theme-toggle-btn:hover {
  background: var(--bg-card);
}

/* ── Sidebar ── */
.sidebar {
  width: var(--sidebar-width);
  background: var(--bg-secondary);
  border-right: 1px solid var(--border);
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  overflow-y: auto;
  z-index: 150;
  display: flex;
  flex-direction: column;
  transition: transform 0.2s ease;
}

.sidebar-header {
  padding: 1rem 1.25rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.sidebar-brand {
  font-weight: 700;
  font-size: 1rem;
  color: var(--text);
}

.sidebar-nav {
  flex: 1;
  padding: 0.5rem 0;
  overflow-y: auto;
}

.nav-section-label {
  padding: 0.75rem 1.25rem 0.25rem;
  font-size: 0.7rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
}

.nav-link {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.45rem 1.25rem;
  color: var(--text-muted);
  font-size: 0.9rem;
  transition: color 0.15s, background 0.15s;
  border-radius: 0;
}

.nav-link:hover {
  color: var(--text);
  background: var(--bg-card);
  text-decoration: none;
}

.nav-link.active {
  color: var(--accent);
  background: var(--bg-card);
  border-left: 3px solid var(--accent);
  padding-left: calc(1.25rem - 3px);
}

.sidebar-footer {
  padding: 0.75rem 1.25rem;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-shrink: 0;
}

.sidebar-footer .theme-toggle-btn {
  font-size: 0.85rem;
  padding: 0.25rem 0.6rem;
  gap: 0.3rem;
}

/* ── Overlay (mobile) ── */
.sidebar-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  z-index: 140;
}

/* ── Main content ── */
.main-content {
  margin-left: var(--sidebar-width);
  flex: 1;
  min-height: 100vh;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 1.5rem;
}

.page-header { margin-bottom: 2rem; }
.page-header h1 { font-size: 1.5rem; }
.page-header .subtitle { color: var(--text-muted); font-size: 0.9rem; margin-top: 0.25rem; }

/* ── Cards ── */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
  margin-bottom: 1rem;
}

.card-title {
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
  margin-bottom: 0.5rem;
}

.stat-value {
  font-size: 2rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1;
}

.stat-label { font-size: 0.85rem; color: var(--text-muted); margin-top: 0.25rem; }

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 1rem;
  margin-bottom: 1.5rem;
}

/* ── Charts ── */
.chart-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

@media (max-width: 900px) {
  .chart-grid { grid-template-columns: 1fr; }
}

.chart-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
}

.chart-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: 1rem;
}

.chart-card svg { display: block; width: 100%; overflow: visible; }
.chart-card.full-width { grid-column: 1 / -1; }

/* ── Badge ── */
.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.badge-codex { background: #1f6feb33; color: #58a6ff; border: 1px solid #1f6feb66; }
.badge-claude { background: #6e40c933; color: #bc8cff; border: 1px solid #6e40c966; }
.badge-gemini { background: #1a7f3733; color: #3fb950; border: 1px solid #1a7f3766; }
.badge-unknown { background: #30363d33; color: #8b949e; border: 1px solid #30363d66; }

/* ── Tab bar ── */
.tab-bar {
  display: flex;
  gap: 0.25rem;
  margin-bottom: 1.25rem;
  flex-wrap: wrap;
}

.tab-btn {
  background: var(--bg-card);
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 0.35rem 0.9rem;
  border-radius: 6px;
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s;
}

.tab-btn:hover { color: var(--text); border-color: var(--accent); }
.tab-btn.active { color: var(--accent); border-color: var(--accent); background: var(--bg-secondary); }

/* ── Messages ── */
.messages { display: flex; flex-direction: column; gap: 0.75rem; margin-top: 1rem; }

.message {
  border-radius: 8px;
  padding: 1rem;
  border: 1px solid;
  max-width: 100%;
}

.message-user {
  background: var(--user-bg);
  border-color: var(--user-border);
  align-self: flex-start;
}

.message-assistant {
  background: var(--assistant-bg);
  border-color: var(--assistant-border);
}

.message-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.message-role {
  font-weight: 600;
  font-size: 0.8rem;
  text-transform: capitalize;
}

.message-user .message-role { color: #58a6ff; }
.message-assistant .message-role { color: #8b949e; }

.message-body { font-size: 0.9rem; line-height: 1.7; word-break: break-word; }
.message-body p { margin-bottom: 0.5rem; }
.message-body p:last-child { margin-bottom: 0; }

/* ── Summary card ── */
.summary-card {
  background: #161b22;
  border: 1px solid #30363d;
  border-left: 3px solid var(--accent);
  border-radius: 6px;
  padding: 1rem 1.25rem;
  margin-bottom: 1.25rem;
  font-size: 0.9rem;
  color: var(--text-muted);
}

.summary-card .summary-label {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--accent);
  margin-bottom: 0.4rem;
}

/* ── Metadata table ── */
.meta-table { font-size: 0.85rem; margin-bottom: 1.25rem; }
.meta-table td:first-child { color: var(--text-muted); width: 140px; font-weight: 500; }

/* ── Backlinks ── */
.backlinks {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.75rem 1rem;
  margin-bottom: 1.25rem;
  font-size: 0.85rem;
}

.backlinks-title { font-weight: 600; color: var(--text-muted); margin-bottom: 0.4rem; font-size: 0.8rem; text-transform: uppercase; }
.backlinks ul { padding-left: 1rem; }

/* ── Search ── */
.search-box {
  width: 100%;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  color: var(--text);
  font-size: 1rem;
  font-family: inherit;
  margin-bottom: 1rem;
  outline: none;
  transition: border-color 0.15s;
}

.search-box:focus { border-color: var(--accent); }

.search-results { display: flex; flex-direction: column; gap: 0.75rem; }

.search-result {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  transition: border-color 0.15s;
}

.search-result:hover { border-color: var(--accent); }
.search-result-title { font-weight: 600; margin-bottom: 0.25rem; }
.search-result-meta { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 0.5rem; }
.search-result-snippet { font-size: 0.85rem; color: var(--text-muted); }
.search-result mark { background: #3d3000; color: var(--warning); border-radius: 2px; padding: 0 0.1em; }
#search-count { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 0.75rem; }

/* ── Heatmap legend ── */
.heatmap-legend {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.5rem;
  justify-content: flex-end;
}

/* ── Popover ── */
.popover {
  position: fixed;
  z-index: 500;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  max-width: 320px;
  font-size: 0.85rem;
  box-shadow: 0 8px 24px rgba(0,0,0,0.4);
  pointer-events: none;
}

.popover-meta { color: var(--text-muted); font-size: 0.78rem; margin-bottom: 0.4rem; }
.popover-summary { color: var(--text); line-height: 1.5; }

/* ── Graph canvas ── */
#graph-canvas {
  display: block;
  width: 100%;
  height: 600px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--bg-secondary);
  cursor: grab;
}

#graph-canvas:active { cursor: grabbing; }

.graph-legend {
  display: flex;
  gap: 1.25rem;
  flex-wrap: wrap;
  margin-top: 0.75rem;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.graph-legend-item {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.graph-legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

/* ── Project cards ── */
.project-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.project-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
  transition: border-color 0.15s;
}

.project-card:hover { border-color: var(--accent); }
.project-card-name { font-weight: 700; font-size: 1.05rem; margin-bottom: 0.5rem; }
.project-card-meta { font-size: 0.82rem; color: var(--text-muted); }
.project-card-clients { margin-top: 0.6rem; display: flex; gap: 0.35rem; flex-wrap: wrap; }

/* ── Responsive: tablet (768-1024px) ── */
@media (max-width: 1024px) and (min-width: 769px) {
  :root { --sidebar-width: 200px; }
}

/* ── Responsive: mobile (<768px) ── */
@media (max-width: 768px) {
  .topbar { display: flex; }
  .sidebar {
    transform: translateX(-100%);
    top: 48px;
  }
  .sidebar.open { transform: translateX(0); }
  .sidebar-overlay.open { display: block; }
  .main-content { margin-left: 0; }
  .container { padding: 1rem 0.75rem; }
  .stats-grid { grid-template-columns: repeat(2, 1fr); }
  .project-grid { grid-template-columns: 1fr; }
}
`

/**
 * GitHub Dark-inspired CSS for the report website.
 * Self-contained — no external CDN dependencies.
 * Supports dark (default) and light themes, sidebar navigation, responsive layout.
 */

export const REPORT_CSS = `
:root {
  --bg: #0d1117;
  --bg-secondary: #161b22;
  --bg-card: #21262d;
  --border: #30363d;
  --text: #e6edf3;
  --text-muted: #8b949e;
  --accent: #58a6ff;
  --accent-hover: #79b8ff;
  --green-0: #161b22;
  --green-1: #0e4429;
  --green-2: #006d32;
  --green-3: #26a641;
  --green-4: #39d353;
  --user-bg: #1c2d3e;
  --user-border: #388bfd44;
  --assistant-bg: #1c1c1c;
  --assistant-border: #30363d;
  --code-bg: #161b22;
  --badge-codex: #1f6feb;
  --badge-claude: #6e40c9;
  --badge-gemini: #1a7f37;
  --danger: #f85149;
  --warning: #d29922;
  --success: #3fb950;
  --sidebar-width: 240px;
  --font-mono: 'SF Mono', 'Consolas', 'Liberation Mono', 'Menlo', monospace;
}

[data-theme="light"] {
  --bg: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-card: #ffffff;
  --border: #d0d7de;
  --text: #1f2328;
  --text-muted: #636c76;
  --accent: #0969da;
  --accent-hover: #0550ae;
  --user-bg: #ddf4ff;
  --user-border: #54aeff44;
  --assistant-bg: #f6f8fa;
  --assistant-border: #d0d7de;
  --code-bg: #f6f8fa;
  --green-0: #f6f8fa;
  --green-1: #acf2bd;
  --green-2: #40c463;
  --green-3: #30a14e;
  --green-4: #216e39;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); text-decoration: underline; }

code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--code-bg);
  padding: 0.15em 0.4em;
  border-radius: 4px;
  border: 1px solid var(--border);
}

pre {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75rem 0;
}

pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.875rem;
}

h1, h2, h3, h4, h5, h6 {
  color: var(--text);
  line-height: 1.3;
  margin-bottom: 0.5rem;
}

h1 { font-size: 1.75rem; }
h2 { font-size: 1.375rem; border-bottom: 1px solid var(--border); padding-bottom: 0.4rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }
h3 { font-size: 1.125rem; }

p { margin-bottom: 0.75rem; }

ul, ol { padding-left: 1.5rem; margin-bottom: 0.75rem; }
li { margin-bottom: 0.25rem; }

table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
th, td { padding: 0.5rem 0.75rem; text-align: left; border-bottom: 1px solid var(--border); }
th { color: var(--text-muted); font-weight: 600; font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.05em; background: var(--bg-secondary); }
tr:hover td { background: var(--bg-secondary); }

/* ── Mobile topbar ── */
.topbar {
  display: none;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  padding: 0 1rem;
  align-items: center;
  gap: 0.75rem;
  height: 48px;
  position: sticky;
  top: 0;
  z-index: 200;
}

.topbar-brand {
  font-weight: 700;
  font-size: 0.95rem;
  color: var(--text);
  flex: 1;
}

.topbar-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.hamburger, .theme-toggle-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 6px;
  padding: 0.3rem 0.5rem;
  cursor: pointer;
  font-size: 1rem;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.hamburger:hover, .theme-toggle-btn:hover {
  background: var(--bg-card);
}

/* ── Sidebar ── */
.sidebar {
  width: var(--sidebar-width);
  background: var(--bg-secondary);
  border-right: 1px solid var(--border);
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  overflow-y: auto;
  z-index: 150;
  display: flex;
  flex-direction: column;
  transition: transform 0.2s ease;
}

.sidebar-header {
  padding: 1rem 1.25rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.sidebar-brand {
  font-weight: 700;
  font-size: 1rem;
  color: var(--text);
}

.sidebar-nav {
  flex: 1;
  padding: 0.5rem 0;
  overflow-y: auto;
}

.nav-section-label {
  padding: 0.75rem 1.25rem 0.25rem;
  font-size: 0.7rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
}

.nav-link {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.45rem 1.25rem;
  color: var(--text-muted);
  font-size: 0.9rem;
  transition: color 0.15s, background 0.15s;
  border-radius: 0;
}

.nav-link:hover {
  color: var(--text);
  background: var(--bg-card);
  text-decoration: none;
}

.nav-link.active {
  color: var(--accent);
  background: var(--bg-card);
  border-left: 3px solid var(--accent);
  padding-left: calc(1.25rem - 3px);
}

.sidebar-footer {
  padding: 0.75rem 1.25rem;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-shrink: 0;
}

.sidebar-footer .theme-toggle-btn {
  font-size: 0.85rem;
  padding: 0.25rem 0.6rem;
  gap: 0.3rem;
}

/* ── Overlay (mobile) ── */
.sidebar-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  z-index: 140;
}

/* ── Main content ── */
.main-content {
  margin-left: var(--sidebar-width);
  flex: 1;
  min-height: 100vh;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 1.5rem;
}

.page-header { margin-bottom: 2rem; }
.page-header h1 { font-size: 1.5rem; }
.page-header .subtitle { color: var(--text-muted); font-size: 0.9rem; margin-top: 0.25rem; }

/* ── Cards ── */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
  margin-bottom: 1rem;
}

.card-title {
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
  margin-bottom: 0.5rem;
}

.stat-value {
  font-size: 2rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1;
}

.stat-label { font-size: 0.85rem; color: var(--text-muted); margin-top: 0.25rem; }

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 1rem;
  margin-bottom: 1.5rem;
}

/* ── Charts ── */
.chart-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

@media (max-width: 900px) {
  .chart-grid { grid-template-columns: 1fr; }
}

.chart-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
}

.chart-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: 1rem;
}

.chart-card svg { display: block; width: 100%; overflow: visible; }
.chart-card.full-width { grid-column: 1 / -1; }

/* ── Badge ── */
.badge {
  display: inline-block;
  padding: 0.2em 0.6em;
  border-radius: 12px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.badge-codex { background: #1f6feb33; color: #58a6ff; border: 1px solid #1f6feb66; }
.badge-claude { background: #6e40c933; color: #bc8cff; border: 1px solid #6e40c966; }
.badge-gemini { background: #1a7f3733; color: #3fb950; border: 1px solid #1a7f3766; }
.badge-unknown { background: #30363d33; color: #8b949e; border: 1px solid #30363d66; }

/* ── Tab bar ── */
.tab-bar {
  display: flex;
  gap: 0.25rem;
  margin-bottom: 1.25rem;
  flex-wrap: wrap;
}

.tab-btn {
  background: var(--bg-card);
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 0.35rem 0.9rem;
  border-radius: 6px;
  font-size: 0.85rem;
  cursor: pointer;
  transition: all 0.15s;
}

.tab-btn:hover { color: var(--text); border-color: var(--accent); }
.tab-btn.active { color: var(--accent); border-color: var(--accent); background: var(--bg-secondary); }

/* ── Messages ── */
.messages { display: flex; flex-direction: column; gap: 0.75rem; margin-top: 1rem; }

.message {
  border-radius: 8px;
  padding: 1rem;
  border: 1px solid;
  max-width: 100%;
}

.message-user {
  background: var(--user-bg);
  border-color: var(--user-border);
  align-self: flex-start;
}

.message-assistant {
  background: var(--assistant-bg);
  border-color: var(--assistant-border);
}

.message-header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.message-role {
  font-weight: 600;
  font-size: 0.8rem;
  text-transform: capitalize;
}

.message-user .message-role { color: #58a6ff; }
.message-assistant .message-role { color: #8b949e; }

.message-body { font-size: 0.9rem; line-height: 1.7; word-break: break-word; }
.message-body p { margin-bottom: 0.5rem; }
.message-body p:last-child { margin-bottom: 0; }

/* ── Summary card ── */
.summary-card {
  background: #161b22;
  border: 1px solid #30363d;
  border-left: 3px solid var(--accent);
  border-radius: 6px;
  padding: 1rem 1.25rem;
  margin-bottom: 1.25rem;
  font-size: 0.9rem;
  color: var(--text-muted);
}

.summary-card .summary-label {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--accent);
  margin-bottom: 0.4rem;
}

/* ── Metadata table ── */
.meta-table { font-size: 0.85rem; margin-bottom: 1.25rem; }
.meta-table td:first-child { color: var(--text-muted); width: 140px; font-weight: 500; }

/* ── Backlinks ── */
.backlinks {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 0.75rem 1rem;
  margin-bottom: 1.25rem;
  font-size: 0.85rem;
}

.backlinks-title { font-weight: 600; color: var(--text-muted); margin-bottom: 0.4rem; font-size: 0.8rem; text-transform: uppercase; }
.backlinks ul { padding-left: 1rem; }

/* ── Search ── */
.search-box {
  width: 100%;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  color: var(--text);
  font-size: 1rem;
  font-family: inherit;
  margin-bottom: 1rem;
  outline: none;
  transition: border-color 0.15s;
}

.search-box:focus { border-color: var(--accent); }

.search-results { display: flex; flex-direction: column; gap: 0.75rem; }

.search-result {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  transition: border-color 0.15s;
}

.search-result:hover { border-color: var(--accent); }
.search-result-title { font-weight: 600; margin-bottom: 0.25rem; }
.search-result-meta { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 0.5rem; }
.search-result-snippet { font-size: 0.85rem; color: var(--text-muted); }
.search-result mark { background: #3d3000; color: var(--warning); border-radius: 2px; padding: 0 0.1em; }
#search-count { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 0.75rem; }

/* ── Heatmap legend ── */
.heatmap-legend {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.5rem;
  justify-content: flex-end;
}

/* ── Popover ── */
.popover {
  position: fixed;
  z-index: 500;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  max-width: 320px;
  font-size: 0.85rem;
  box-shadow: 0 8px 24px rgba(0,0,0,0.4);
  pointer-events: none;
}

.popover-meta { color: var(--text-muted); font-size: 0.78rem; margin-bottom: 0.4rem; }
.popover-summary { color: var(--text); line-height: 1.5; }

/* ── Graph canvas ── */
#graph-canvas {
  display: block;
  width: 100%;
  height: 600px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--bg-secondary);
  cursor: grab;
}

#graph-canvas:active { cursor: grabbing; }

.graph-legend {
  display: flex;
  gap: 1.25rem;
  flex-wrap: wrap;
  margin-top: 0.75rem;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.graph-legend-item {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.graph-legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

/* ── Project cards ── */
.project-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.project-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
  transition: border-color 0.15s;
}

.project-card:hover { border-color: var(--accent); }
.project-card-name { font-weight: 700; font-size: 1.05rem; margin-bottom: 0.5rem; }
.project-card-meta { font-size: 0.82rem; color: var(--text-muted); }
.project-card-clients { margin-top: 0.6rem; display: flex; gap: 0.35rem; flex-wrap: wrap; }

/* ── Responsive: tablet (768-1024px) ── */
@media (max-width: 1024px) and (min-width: 769px) {
  :root { --sidebar-width: 200px; }
}

/* ── Responsive: mobile (<768px) ── */
@media (max-width: 768px) {
  .topbar { display: flex; }
  .sidebar {
    transform: translateX(-100%);
    top: 48px;
  }
  .sidebar.open { transform: translateX(0); }
  .sidebar-overlay.open { display: block; }
  .main-content { margin-left: 0; }
  .container { padding: 1rem 0.75rem; }
  .stats-grid { grid-template-columns: repeat(2, 1fr); }
  .project-grid { grid-template-columns: 1fr; }
}
`

/**
 * HTML layout helpers: shell, navigation, and HTML escaping.
 */

import { basename } from 'node:path'

import type { ManifestEntry } from '../../types/transcript.js'
import type { Translations } from '../i18n/types.js'
import { REPORT_CSS } from './css.js'

// ---------------------------------------------------------------------------
// HTML escaping
// ---------------------------------------------------------------------------

export function escHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;')
}

// ---------------------------------------------------------------------------
// Navigation page IDs
// ---------------------------------------------------------------------------

export type NavPage =
  | 'dashboard'
  | 'transcripts'
  | 'projects'
  | 'graph'
  | 'goals'
  | 'todos'
  | 'knowledge'
  | 'archive'
  | 'search'

// ---------------------------------------------------------------------------
// Sidebar navigation
// ---------------------------------------------------------------------------

const SIDEBAR_INLINE_JS = `
<script>
(function() {
  // Theme
  var saved = localStorage.getItem('mt-theme') || 'dark';
  document.documentElement.setAttribute('data-theme', saved);
  function updateThemeBtn() {
    var btn = document.getElementById('theme-toggle');
    if (btn) btn.textContent = document.documentElement.getAttribute('data-theme') === 'dark' ? '☀ Light' : '☾ Dark';
  }
  document.addEventListener('DOMContentLoaded', function() {
    updateThemeBtn();
    var btn = document.getElementById('theme-toggle');
    if (btn) btn.addEventListener('click', function() {
      var next = document.documentElement.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
      document.documentElement.setAttribute('data-theme', next);
      localStorage.setItem('mt-theme', next);
      updateThemeBtn();
    });
    // Mobile hamburger
    var hb = document.getElementById('hamburger');
    var sb = document.getElementById('sidebar');
    var ov = document.getElementById('sidebar-overlay');
    function closeSidebar() {
      if (sb) sb.classList.remove('open');
      if (ov) ov.classList.remove('open');
    }
    if (hb) hb.addEventListener('click', function() {
      if (sb) sb.classList.toggle('open');
      if (ov) ov.classList.toggle('open');
    });
    if (ov) ov.addEventListener('click', closeSidebar);
    // Popover preview
    var popover = null;
    document.querySelectorAll('a[data-summary]').forEach(function(el) {
      el.addEventListener('mouseenter', function(e) {
        var summary = el.getAttribute('data-summary') || '';
        var meta = el.getAttribute('data-meta') || '';
        if (!summary && !meta) return;
        if (!popover) {
          popover = document.createElement('div');
          popover.className = 'popover';
          document.body.appendChild(popover);
        }
        popover.innerHTML = (meta ? '<div class="popover-meta">' + meta + '</div>' : '') +
          (summary ? '<div class="popover-summary">' + summary + '</div>' : '');
        popover.style.display = 'block';
        positionPopover(e);
      });
      el.addEventListener('mousemove', positionPopover);
      el.addEventListener('mouseleave', function() {
        if (popover) popover.style.display = 'none';
      });
    });
    function positionPopover(e) {
      if (!popover) return;
      var x = e.clientX + 12;
      var y = e.clientY + 12;
      var pw = popover.offsetWidth || 320;
      var ph = popover.offsetHeight || 80;
      if (x + pw > window.innerWidth - 8) x = e.clientX - pw - 12;
      if (y + ph > window.innerHeight - 8) y = e.clientY - ph - 12;
      popover.style.left = x + 'px';
      popover.style.top = y + 'px';
    }
  });
})();
</script>`

interface NavItem {
  id: NavPage
  icon: string
  labelKey: keyof Translations['nav']
  href: string
}

function buildNavItems(rootLevel: boolean): NavItem[] {
  const p = rootLevel ? '' : '../'
  return [
    { id: 'dashboard', icon: '◈', labelKey: 'dashboard', href: `${p}index.html` },
    { id: 'transcripts', icon: '💬', labelKey: 'sessions', href: `${p}transcripts/index.html` },
    { id: 'projects', icon: '📁', labelKey: 'projects', href: `${p}projects/index.html` },
    { id: 'graph', icon: '⬡', labelKey: 'graph', href: `${p}graph.html` },
    { id: 'goals', icon: '🎯', labelKey: 'goals', href: `${p}goals/index.html` },
    { id: 'todos', icon: '✓', labelKey: 'todos', href: `${p}todos/index.html` },
    { id: 'knowledge', icon: '📚', labelKey: 'knowledge', href: `${p}knowledge/index.html` },
    { id: 'archive', icon: '🗄', labelKey: 'archive', href: `${p}archive/index.html` },
    { id: 'search', icon: '🔍', labelKey: 'search', href: `${p}search.html` },
  ]
}

export function renderNav(current: NavPage, rootLevel: boolean, t?: Translations): string {
  const items = buildNavItems(rootLevel)

  // Labels for each nav item
  const label = (item: NavItem): string => {
    if (t) return t.nav[item.labelKey]
    // Fallback English labels
    const defaults: Record<string, string> = {
      dashboard: 'Dashboard', sessions: 'Sessions', projects: 'Projects',
      graph: 'Graph', goals: 'Goals', todos: 'Todos',
      knowledge: 'Knowledge', archive: 'Archive', search: 'Search',
    }
    return defaults[item.labelKey] ?? item.labelKey
  }

  const themeLabel = '☀ Light'

  const navLinks = items.map(item => {
    const cls = item.id === current ? 'nav-link active' : 'nav-link'
    return `<a href="${escHtml(item.href)}" class="${cls}">${escHtml(item.icon)} ${escHtml(label(item))}</a>`
  }).join('\n      ')

  return `<aside class="sidebar" id="sidebar">
  <div class="sidebar-header">
    <span class="sidebar-brand">MemoryTree</span>
  </div>
  <nav class="sidebar-nav">
    ${navLinks}
  </nav>
  <div class="sidebar-footer">
    <button class="theme-toggle-btn" id="theme-toggle" type="button">${escHtml(themeLabel)}</button>
  </div>
</aside>
<div class="sidebar-overlay" id="sidebar-overlay"></div>`
}

