  for (var m = 0; m < N; m++) {
    var node = simNodes[m];
    node.vx += -node.x * CENTER_FORCE * ALPHA;
    node.vy += -node.y * CENTER_FORCE * ALPHA;
    if (node === dragNode) continue;
    node.vx *= DAMPING;
    node.vy *= DAMPING;
    node.x += node.vx;
    node.y += node.vy;
  }
