/**
 * GitHub Pages deployment: push report output to gh-pages branch.
 */

import { writeFileSync, existsSync } from 'node:fs'
import { join } from 'node:path'
import { execSync } from 'node:child_process'

import { getLogger } from '../../heartbeat/log.js'

export interface GithubPagesOptions {
  /** Repository root (contains .git/) */
  repoRoot: string
  /** Report output directory (e.g. Memory/07_reports) */
  outputDir: string
  /** Branch name to push to (e.g. 'gh-pages'). Empty string = skip. */
  branch: string
  /** Custom domain (CNAME). Empty string = skip. */
  cname: string
}

export async function deployGithubPages(options: GithubPagesOptions): Promise<void> {
  const { repoRoot, outputDir, branch, cname } = options
  const logger = getLogger()

  if (!branch) return

  try {
    // 1. Write CNAME file if configured
    if (cname) {
      const cnamePath = join(outputDir, 'CNAME')
      writeFileSync(cnamePath, cname + '\n', 'utf-8')
      logger.info(`[gh-pages] CNAME written: ${cname}`)
    }

    // 2. Check if branch exists on remote
    let branchExists = false
    try {
      execSafe(repoRoot, `git ls-remote --exit-code --heads origin ${branch}`)
      branchExists = true
    } catch {
      branchExists = false
    }

    if (!branchExists) {
      // Create orphan branch with an empty commit
      logger.info(`[gh-pages] Branch '${branch}' not found, creating orphan...`)
      const worktreePath = join(repoRoot, '.git', 'gh-pages-init-worktree')
      try {
        execSafe(repoRoot, `git worktree add --orphan -b ${branch} "${worktreePath}"`)
        execSafe(worktreePath, 'git commit --allow-empty -m "chore: init gh-pages"')
        execSafe(repoRoot, `git push origin ${branch}`)
      } finally {
        try { execSafe(repoRoot, `git worktree remove --force "${worktreePath}"`) } catch { /* ignore */ }
      }
    }

    // 3. Push using git subtree
    // Compute relative path of outputDir from repoRoot
    const relOutput = makeRelative(repoRoot, outputDir)
    logger.info(`[gh-pages] Pushing ${relOutput} to origin/${branch}...`)
    execSafe(repoRoot, `git subtree push --prefix "${relOutput}" origin ${branch}`)
    logger.info(`[gh-pages] Successfully pushed to origin/${branch}`)
  } catch (err: unknown) {
    logger.warn(`[gh-pages] Deploy failed: ${String(err)}`)
    // Never throw — report deploy failure must not abort heartbeat
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function execSafe(cwd: string, command: string): string {
  return execSync(command, { cwd, stdio: 'pipe' }).toString()
}

function makeRelative(base: string, target: string): string {
  // Normalize separators
  const b = base.replace(/\\/g, '/').replace(/\/$/, '')
  const t = target.replace(/\\/g, '/').replace(/\/$/, '')
  if (t.startsWith(b + '/')) {
    return t.slice(b.length + 1)
  }
  return t
}

