/**
 * Webhook notification: sends a POST to configurable endpoints.
 * Supports Feishu, Telegram, Discord, Slack, and generic webhooks.
 * Never throws — failures are logged as warnings.
 */

import { getLogger } from '../../heartbeat/log.js'

export interface WebhookOptions {
  url: string
  sessionCount: number
  newSessionIds?: string[]
  reportUrl?: string
}

// ---------------------------------------------------------------------------
// Platform detection
// ---------------------------------------------------------------------------

type Platform = 'feishu' | 'telegram' | 'discord' | 'slack' | 'generic'

function detectPlatform(url: string): Platform {
  if (url.includes('open.feishu.cn') || url.includes('open.larksuite.com')) return 'feishu'
  if (url.includes('api.telegram.org')) return 'telegram'
  if (url.includes('discord.com/api/webhooks') || url.includes('discordapp.com/api/webhooks')) return 'discord'
  if (url.includes('hooks.slack.com')) return 'slack'
  return 'generic'
}

// ---------------------------------------------------------------------------
// Payload builders
