        template: 'blue',
      },
      elements: [
        {
          tag: 'div',
          text: {
            tag: 'lark_md',
            content: `**Sessions:** ${sessionCount} total${newCount ? `, ${newCount} new` : ''}`,
          },
        },
        ...(actionBtn.length > 0 ? [{ tag: 'action', actions: actionBtn }] : []),
      ],
    },
  }
}

function buildTelegramPayload(options: WebhookOptions): Record<string, unknown> {
