import { sendWebhook } from '../../src/report/deploy/webhook.js'

// ---------------------------------------------------------------------------
// We test platform detection and payload building logic indirectly
// by observing that no exceptions are thrown and the function resolves.
// Network calls are effectively caught and silently logged.
// ---------------------------------------------------------------------------

describe('sendWebhook — no-op on empty URL', () => {
  it('resolves immediately when url is empty', async () => {
    await expect(sendWebhook({ url: '', sessionCount: 10 })).resolves.not.toThrow()
  })
})

describe('sendWebhook — network failure does not throw', () => {
  it('resolves even when HTTP request fails (invalid URL)', async () => {
    await expect(
      sendWebhook({ url: 'https://localhost:1/nonexistent', sessionCount: 5 })
    ).resolves.not.toThrow()
  })

  it('resolves even for malformed URL', async () => {
    await expect(
      sendWebhook({ url: 'not-a-url', sessionCount: 5 })
    ).resolves.not.toThrow()
  })
})

describe('sendWebhook — platform recognition (via URL patterns)', () => {
  // These tests confirm the function handles different URL patterns without throwing.
  // We cannot easily verify the payload without a real server, but we can confirm
  // that a "feishu" URL is accepted and treated gracefully.

  it('accepts feishu URL (no network call needed — fails gracefully)', async () => {
    await expect(
      sendWebhook({
        url: 'https://open.feishu.cn/open-apis/bot/v2/hook/test',
        sessionCount: 42,
        newSessionIds: ['s1', 's2'],
      })
    ).resolves.not.toThrow()
  })

  it('accepts telegram URL', async () => {
    await expect(
      sendWebhook({
        url: 'https://api.telegram.org/botTEST/sendMessage',
        sessionCount: 10,
      })
    ).resolves.not.toThrow()
  })

  it('accepts discord URL', async () => {
    await expect(
      sendWebhook({
        url: 'https://discord.com/api/webhooks/123/test',
        sessionCount: 5,
        reportUrl: 'https://example.com/report',
      })
    ).resolves.not.toThrow()
  })

  it('accepts slack URL', async () => {
    await expect(
      sendWebhook({
        url: 'https://hooks.slack.com/services/test',
        sessionCount: 7,
      })
    ).resolves.not.toThrow()
  })

  it('accepts generic URL', async () => {
    await expect(
      sendWebhook({
        url: 'https://my-custom-server.example.com/webhook',
        sessionCount: 3,
      })
    ).resolves.not.toThrow()
  })
})

