// ---------------------------------------------------------------------------
// URL safety validation
// ---------------------------------------------------------------------------

/** Private / loopback IP ranges that must not be reachable via webhook. */
const PRIVATE_HOSTNAME_RE =
  /^(localhost|127\.\d+\.\d+\.\d+|0\.0\.0\.0|::1|10\.\d+\.\d+\.\d+|172\.(1[6-9]|2\d|3[01])\.\d+\.\d+|192\.168\.\d+\.\d+|169\.254\.\d+\.\d+|fc[0-9a-f]{2}:|fd[0-9a-f]{2}:)$/i

function validateWebhookUrl(raw: string): URL {
  let url: URL
  try {
    url = new URL(raw)
  } catch {
    throw new Error(`Invalid webhook URL: ${raw}`)
  }
  if (url.protocol !== 'https:') {
    throw new Error(`Webhook URL must use https: (got ${url.protocol})`)
  }
  if (PRIVATE_HOSTNAME_RE.test(url.hostname)) {
    throw new Error(`Webhook URL hostname is private/loopback: ${url.hostname}`)
  }
  return url
}

// ---------------------------------------------------------------------------
// Main send function
// ---------------------------------------------------------------------------

