    const manifests = Array.from({ length: 150 }, (_, i) =>
      makeManifest({ session_id: `sess-${i.toString().padStart(3, '0')}`, started_at: `2026-03-${(i % 28 + 1).toString().padStart(2, '0')}T00:00:00Z` })
