/** Render tags as pill badges. Returns '' for empty array. */
export function renderTagBadges(tags: string[]): string {
  if (tags.length === 0) return ''
  const pills = tags
    .map(t => `<span class="tag" data-tag="${escTag(t)}">${escTag(t)}</span>`)
    .join('')
  return `<div class="tag-list">${pills}</div>`
}

function escTag(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

